var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"보물까지 나아가는 인명의 자국~.","JPN":"お宝めがけて進む人命の跡～","ENG":"The mark of humanity advancing to treasure!","TWN":"通往寶藏的生命足跡～"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"푸른 하늘 바다 위에 함께 서 있네~.","JPN":"青き空と海の上に共に立ち～","ENG":"We stand together on the ocean, beneath the blue sky!","TWN":"藍天大海之上，我們並肩站立～"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"파도에 휩쓸려도 앞으로. 앞으로 나아가리~!","JPN":"波に流されようとも前へ。前へ進む～！","ENG":"And even against the tidal waves, sail forth!","TWN":"即使被浪潮捲走，也要向前、向前進～！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"그 누가……","JPN":"誰が……","ENG":"No one can...","TWN":"沒有誰能……"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":" 저기, 유피.","JPN":" ねえ、ユピ。","ENG":" Hey, Yuppie.","TWN":"那個，悠菲。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"언제까지 그렇게 뒤에만 있을 거야?","JPN":"いつまでずっと後ろにいるつもりなの？","ENG":"How long are you going to stay back there?","TWN":"你要在後面待到什麼時候？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"내버려두세요.","JPN":"ほっといてください。","ENG":"Leave me alone.","TWN":"就這樣丟下我吧。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"모처럼 새 직장을 구하나 싶었는데 이런 꼴이라니… 전 구제할 길 없는 쓰레기예요.","JPN":"せっかく新しい職場が見つかったと思ったのに、こんなだなんて……私は救いようのないクズです。","ENG":"I thought I was going to get a new job, and look where I'm at... I'm just trash with no hope.","TWN":"好不容易找到新工作，結果卻是這樣……我真是無可救藥的圾垃。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이젠 해적이니까 바다의 쓰레기인가? 아하하하!","JPN":"もうすでに海賊だから海のもくずってこと？　あははは！","ENG":"Since I'm a pirate now, I guess I'm the trash in the ocean that's hurting the environment! Ah ha ha ha!","TWN":"現在成了海盜，就是海洋垃圾了嗎？哈哈！哈哈哈哈？！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"안 돼. 해적은 언제 어디서나 당당해야 한다구.","JPN":"ダメだよ。海賊はいつでも堂々としてるべき。","ENG":"No. Pirates should stand proud, no matter when or where.","TWN":"不能這樣，海盜無論何時何地都要抬頭挺胸。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"멋대로 납치한 사람이 할 말인가요, 그게.","JPN":"それ、勝手に私をさらった人のいうセリフですか。","ENG":"How can you say that when you're the one who kidnapped me?","TWN":"這是隨便綁架別人的你該說的話嗎？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"실장님은 좋으시겠네요. 언제 준비하셨는지 수영복으로까지 갈아입으시고.","JPN":"室長はいいですよね。いつの間にか水着にまで着替えて。","ENG":"It should be good for you, though, since you somehow brought a swimsuit and you've already changed.","TWN":"室長很開心呢。趁我不注意的時候，連泳裝都換好啦？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"애초에 빈털터리 두 명이서 대체 뭘 하겠…","JPN":"そもそも一文無しの二人でいったい何ができ……","ENG":"What are two broke girls going to do, anyw–","TWN":"兩個窮光蛋到底能在這裡做什麼……"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":" 응?","JPN":" うん？","ENG":" Hmm?","TWN":"欸？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네! 모네네!","JPN":"モネ！　モネネ！","ENG":"Mone! Monene!","TWN":"莫妮！莫妮妮！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네네네!!","JPN":"モネネネ！！","ENG":"Monenene!","TWN":"莫妮妮妮！！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"펭귄…? 저게 대체 뭐야?","JPN":"ペンギン……？　あれは何？","ENG":"A penguin...? What is that?","TWN":"企鵝…？那到底是……什麼？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그것보다 저 옷. 어디서 본 것 같은…….","JPN":"それよりあの服。どっかで見たような……","ENG":"Wait, that outfit. I think I've seen that before...","TWN":"倒是那件衣服……好像在哪裡見過……"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"찾았다. 귀여운 동물!","JPN":"見つけた。可愛い動物！","ENG":"I found it! Cute animal!","TWN":"找到了，可愛的動物！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"귀여운 동물? 암호에 있던 그거 말인가요?","JPN":"可愛い動物？　暗号にあったアレのことですか？","ENG":"Cute animal? You mean, from the ciphertext?","TWN":"可愛的動物？你是指密碼裡的那個嗎？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"확실히 귀엽기는 한데, 지금은 뭔가 화난 것 같은데요.","JPN":"確かに可愛いですけど、今はなんだか怒ってるみたいですよ。","ENG":"It's definitely cute, but it looks angry right now.","TWN":"確實很可愛，但好像在生氣的樣子。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"RIBBON_DEBT_NPC_NULL","text":{"KOREA":"도움-.","JPN":"助けてー","ENG":"Help–.","TWN":"幫我——"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RIBBON_DEBT_NPC_NULL","text":{"KOREA":"아파서 못 움직이겠어요.","JPN":"痛くて動けないです。","ENG":"I can't move. I'm hurt.","TWN":"好痛，動不了——"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"이상하다? 펭귄 친구들은 착해서 사람을 공격하지 않는데.","JPN":"変だね。ペンギンちゃんたちはいい子だから、人を攻撃したりしないんだけど。","ENG":"That's weird. Penguins are nice, and they don't attack people.","TWN":"奇怪？企鵝朋友們很乖，不會攻擊人的。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"RIBBON_DEBT_NPC_NULL","text":{"KOREA":"크레데레는 땅에 묻힐 만한 잘못은 저지르지 않았습니다.","JPN":"クレデレは地面に埋められるような罪は犯してないです。","ENG":"Credere hasn't done anything to deserve being buried.","TWN":"克蕾妲莉不會犯下足以被埋葬的錯誤。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NPC_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"펭귄분들의 간식을 사재기한 뒤, 통정매매를 통해 값을 올렸을 뿐이에요.","JPN":"ペンギンたちのおやつを買い占めて、市場価格を操縦して値段をつり上げただけです。","ENG":"Credere has done nothing but buy all of the penguins' snacks and raise their price.","TWN":"克蕾妲莉只是買光了企鵝的零食，然後哄抬價格而已。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"가요, 실장님. 제 본능이 벗어나라며 소리치고 있어요.","JPN":"行きましょう、室長。私の本能がここから逃げろと叫んでます。","ENG":"Let's go, Chief. My instincts are telling me to get away.","TWN":"走吧，室長。我的本能在大喊讓我離開這裡。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"더 이상 귀찮은 일은 사절이라고요.","JPN":"もう面倒なことはゴメンなんです。","ENG":"This is just going to be more of a hassle.","TWN":"我可不想再被捲入麻煩事裡了。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"안 돼. 진정한 해적은 도움을 필요로 하는 사람을 외면하지 않아.","JPN":"ダメだよ。真の海賊は、助けを求める人から目を背けない。","ENG":"No. A true pirate never ignores those in need.","TWN":"不行，真正的海盜不會無視需要幫助的人。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그러니까 그건 해적이 아니래도요?","JPN":"だから、それは海賊じゃないですよ？","ENG":"That's not what a pirate do.","TWN":"海盜是這種人設嗎？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"적어도 시그마 해적단은 그래!","JPN":"少なくともシグマ海賊団はそうなの！","ENG":"At least that's how the Sigma Pirates operate!","TWN":"至少西格瑪海盜團是這樣！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"가자, 유피 선원. 신생 시그마 해적단의 영광스러운 첫 출전이다!","JPN":"行こう、ユピ船員。新生シグマ海賊団の光栄なる初出陣だ！","ENG":"Let's go, Yuppie. This is the glorious first journey of the new Sigma Pirates!","TWN":"出發吧，悠菲船員。這是全新的西格瑪海盜團光榮的首次出戰！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L48_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"으으.","JPN":"うう。","ENG":"Ugh.","TWN":"呃呃。"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"먹고 살기 더럽게 힘드네, 젠장!","JPN":"人生ってキツすぎるよ、クソ！","ENG":"Damn it, I'm just trying to make ends meet! Why does it have to be this hard?!","TWN":"人生好難，討厭！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};